local UIObjPool = LxClass("UIObjPool", nil)

function UIObjPool:Create(unuseRoot,template)
    self._unuseRoot  = unuseRoot
    self._template = template
    self._pool = {}
    self._used = {}
end

function UIObjPool:GetObj()
    local obj = table.remove(self._pool)
    if not obj then
        obj = LxResUtil.NewObject(self._template)
    end
    table.insert(self._used,obj)
    return obj
end

function UIObjPool:ReturnAllObj()
    while true do
        local obj = table.remove(self._used)
        if not obj then
            return
        end
        obj.transform:SetParent(self._unuseRoot.transform)
        table.insert(self._pool,obj)
    end
end
function UIObjPool:ReturnObj(obj)
    local index = nil
    for k,v in ipairs(self._used) do
        if v == obj then
            index = k
            break
        end
    end
    if index then
        table.remove(self._used,index)
        obj.transform:SetParent(self._unuseRoot.transform)
        table.insert(self._pool,obj)
    end

end

function UIObjPool:DestroyAllObj()
    self:ReturnAllObj()
    if self._pool then
        for k,v in ipairs(self._pool) do
            LxResUtil.DestroyObject(v.gameObject)
        end
    end

    self:Destroy()
end

function UIObjPool:Destroy()
    table.removeall(self)
end

return UIObjPool